package persona

import (
	"bufio"
	"bytes"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"gopkg.in/yaml.v3"
)

// PersonaLoaderImpl implements the PersonaLoader interface.
//
// A loader can own up to two source directories:
//   - libraryDir: read-only, shared across projects.
//   - projectDir: project-local (`.ddx/personas`). When a project persona has
//     the same name as a library persona, the project persona wins for that
//     project's bindings.
type PersonaLoaderImpl struct {
	// libraryDir is the legacy single directory and remains in use when the
	// loader is constructed via NewPersonaLoaderWithDir for test fixtures.
	personasDir string
	projectDir  string
}

// NewPersonaLoader creates a new persona loader rooted at the project's
// working directory. It discovers the library path from config and the
// project-local `.ddx/personas` directory.
func NewPersonaLoader(workingDir string) PersonaLoader {
	libraryDir := resolveLibraryPersonasDir(workingDir)
	projectDir := resolveProjectPersonasDir(workingDir)
	return &PersonaLoaderImpl{
		personasDir: libraryDir,
		projectDir:  projectDir,
	}
}

// NewPersonaLoaderWithDir creates a new persona loader with a specific
// library directory. Kept for tests and back-compat callers that only need
// the library source.
func NewPersonaLoaderWithDir(dir string) PersonaLoader {
	return &PersonaLoaderImpl{
		personasDir: dir,
	}
}

// NewPersonaLoaderWithDirs creates a loader with explicit library and project
// directories. Either may be empty to disable that source.
func NewPersonaLoaderWithDirs(libraryDir, projectDir string) PersonaLoader {
	return &PersonaLoaderImpl{
		personasDir: libraryDir,
		projectDir:  projectDir,
	}
}

// resolveLibraryPersonasDir resolves the library persona directory.
func resolveLibraryPersonasDir(workingDir string) string {
	cfg, err := config.LoadWithWorkingDir(workingDir)
	if err != nil || cfg.Library == nil || cfg.Library.Path == "" {
		homeDir, _ := os.UserHomeDir()
		return filepath.Join(homeDir, ".ddx", "plugins", "ddx", "personas")
	}
	libPath := cfg.Library.Path
	if !filepath.IsAbs(libPath) && workingDir != "" {
		libPath = filepath.Join(workingDir, libPath)
	}
	return filepath.Join(libPath, "personas")
}

// resolveProjectPersonasDir returns the project-local persona directory.
func resolveProjectPersonasDir(workingDir string) string {
	if workingDir == "" {
		return ""
	}
	return filepath.Join(workingDir, ".ddx", "personas")
}

// LoadPersona loads a persona by name. Project-local personas override
// library personas with the same name.
func (l *PersonaLoaderImpl) LoadPersona(name string) (*Persona, error) {
	if name == "" {
		return nil, NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
	}

	if l.projectDir != "" {
		candidate := filepath.Join(l.projectDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceProject)
		}
	}

	if l.personasDir != "" {
		candidate := filepath.Join(l.personasDir, name+PersonaFileExtension)
		if fileExists(candidate) {
			return readPersonaFile(candidate, SourceLibrary)
		}
	}

	return nil, NewPersonaError(ErrorPersonaNotFound,
		fmt.Sprintf("persona '%s' not found", name), nil)
}

// readPersonaFile reads a single persona file and tags it with its source.
func readPersonaFile(filePath, source string) (*Persona, error) {
	content, err := os.ReadFile(filePath)
	if err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to read persona file %s", filePath), err)
	}
	if len(content) > MaxPersonaFileSize {
		return nil, NewPersonaError(ErrorValidation,
			fmt.Sprintf("persona file %s exceeds maximum size of %d bytes", filePath, MaxPersonaFileSize), nil)
	}
	persona, err := parsePersona(content)
	if err != nil {
		return nil, NewPersonaError(ErrorInvalidPersona,
			fmt.Sprintf("failed to parse persona %s", filePath), err)
	}
	persona.Source = source
	persona.FilePath = filePath
	return persona, nil
}

// ListPersonas returns all available personas. Project personas override
// library personas of the same name; both sets are listed, with the project
// persona taking precedence when names collide.
func (l *PersonaLoaderImpl) ListPersonas() ([]*Persona, error) {
	// Project personas first so they win on collision.
	byName := map[string]*Persona{}
	var ordered []string

	for _, dir := range []struct {
		path   string
		source string
	}{
		{l.projectDir, SourceProject},
		{l.personasDir, SourceLibrary},
	} {
		if dir.path == "" || !dirExists(dir.path) {
			continue
		}
		entries, err := os.ReadDir(dir.path)
		if err != nil {
			return nil, NewPersonaError(ErrorFileOperation,
				fmt.Sprintf("failed to read personas directory %s", dir.path), err)
		}
		for _, entry := range entries {
			if entry.IsDir() {
				continue
			}
			if !strings.HasSuffix(entry.Name(), PersonaFileExtension) {
				continue
			}
			if entry.Name() == "README.md" || entry.Name() == "readme.md" {
				continue
			}
			personaName := strings.TrimSuffix(entry.Name(), PersonaFileExtension)
			if _, seen := byName[personaName]; seen {
				continue
			}
			persona, err := readPersonaFile(filepath.Join(dir.path, entry.Name()), dir.source)
			if err != nil {
				_, _ = fmt.Fprintf(os.Stderr, "Warning: Skipping invalid persona %s: %v\n", entry.Name(), err)
				continue
			}
			byName[personaName] = persona
			ordered = append(ordered, personaName)
		}
	}

	result := make([]*Persona, 0, len(byName))
	for _, name := range ordered {
		result = append(result, byName[name])
	}
	return result, nil
}

// FindByRole returns personas that can fulfill the specified role.
func (l *PersonaLoaderImpl) FindByRole(role string) ([]*Persona, error) {
	if role == "" {
		return nil, NewPersonaError(ErrorValidation, "role cannot be empty", nil)
	}

	allPersonas, err := l.ListPersonas()
	if err != nil {
		return nil, err
	}

	var matchingPersonas []*Persona

	for _, persona := range allPersonas {
		for _, personaRole := range persona.Roles {
			if personaRole == role {
				matchingPersonas = append(matchingPersonas, persona)
				break
			}
		}
	}

	return matchingPersonas, nil
}

// FindByTags returns personas that have all the specified tags.
func (l *PersonaLoaderImpl) FindByTags(tags []string) ([]*Persona, error) {
	if len(tags) == 0 {
		return nil, NewPersonaError(ErrorValidation, "at least one tag must be specified", nil)
	}

	allPersonas, err := l.ListPersonas()
	if err != nil {
		return nil, err
	}

	var matchingPersonas []*Persona

	for _, persona := range allPersonas {
		if hasAllTags(persona.Tags, tags) {
			matchingPersonas = append(matchingPersonas, persona)
		}
	}

	return matchingPersonas, nil
}

// parsePersona parses a persona from markdown content with YAML frontmatter.
func parsePersona(content []byte) (*Persona, error) {
	frontmatter, markdownContent, err := splitFrontmatter(content)
	if err != nil {
		return nil, err
	}

	var persona Persona
	if err := yaml.Unmarshal(frontmatter, &persona); err != nil {
		return nil, NewPersonaError(ErrorInvalidPersona, "failed to parse YAML frontmatter", err)
	}

	persona.Content = string(markdownContent)

	if err := validatePersona(&persona); err != nil {
		return nil, err
	}

	return &persona, nil
}

// splitFrontmatter splits YAML frontmatter from markdown content.
func splitFrontmatter(content []byte) (frontmatter []byte, markdown []byte, err error) {
	scanner := bufio.NewScanner(bytes.NewReader(content))

	var lines []string
	for scanner.Scan() {
		lines = append(lines, scanner.Text())
	}

	if len(lines) < 2 {
		return nil, nil, NewPersonaError(ErrorInvalidPersona, "file too short to contain frontmatter", nil)
	}

	if lines[0] != "---" {
		return nil, nil, NewPersonaError(ErrorInvalidPersona, "missing YAML frontmatter (must start with ---)", nil)
	}

	frontmatterEnd := -1
	for i := 1; i < len(lines); i++ {
		if lines[i] == "---" {
			frontmatterEnd = i
			break
		}
	}

	if frontmatterEnd == -1 {
		return nil, nil, NewPersonaError(ErrorInvalidPersona, "unclosed YAML frontmatter (missing closing ---)", nil)
	}

	frontmatterLines := lines[1:frontmatterEnd]
	frontmatter = []byte(strings.Join(frontmatterLines, "\n"))

	var markdownLines []string
	if frontmatterEnd+1 < len(lines) {
		markdownLines = lines[frontmatterEnd+1:]
		for len(markdownLines) > 0 && strings.TrimSpace(markdownLines[0]) == "" {
			markdownLines = markdownLines[1:]
		}
	}

	markdown = []byte(strings.Join(markdownLines, "\n"))

	return frontmatter, markdown, nil
}

// validatePersona validates that a persona has all required fields.
func validatePersona(persona *Persona) error {
	if persona.Name == "" {
		return NewPersonaError(ErrorValidation, "persona name is required", nil)
	}

	if len(persona.Roles) == 0 {
		return NewPersonaError(ErrorValidation, "persona must have at least one role", nil)
	}

	if persona.Description == "" {
		return NewPersonaError(ErrorValidation, "persona description is required", nil)
	}

	if len(persona.Roles) > MaxRolesPerPersona {
		return NewPersonaError(ErrorValidation,
			fmt.Sprintf("persona cannot have more than %d roles", MaxRolesPerPersona), nil)
	}

	if len(persona.Tags) > MaxTagsPerPersona {
		return NewPersonaError(ErrorValidation,
			fmt.Sprintf("persona cannot have more than %d tags", MaxTagsPerPersona), nil)
	}

	if persona.Tags == nil {
		persona.Tags = []string{}
	}

package persona

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

// ProjectPersonaWriter owns create/update/delete operations for project-local
// personas (files under `.ddx/personas/*.md`). Library personas are never
// mutated by this type; attempting to do so returns an ErrorReadOnlyLibrary.
type ProjectPersonaWriter struct {
	workingDir string
	loader     *PersonaLoaderImpl
}

// NewProjectPersonaWriter returns a writer rooted at the given working
// directory. Passing an empty working dir returns a writer that errors on
// all calls because there is no project context.
func NewProjectPersonaWriter(workingDir string) *ProjectPersonaWriter {
	loader := &PersonaLoaderImpl{
		personasDir: resolveLibraryPersonasDir(workingDir),
		projectDir:  resolveProjectPersonasDir(workingDir),
	}
	return &ProjectPersonaWriter{workingDir: workingDir, loader: loader}
}

// Create writes a new project-local persona. Fails if a project persona
// with the same name already exists. A library persona with the same name
// is allowed (the project file will override it).
func (w *ProjectPersonaWriter) Create(name string, body string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to create a persona", nil)
	}
	if err := validateName(name); err != nil {
		return nil, err
	}
	dir := w.loader.projectDir
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to create project personas directory %s", dir), err)
	}
	filePath := filepath.Join(dir, name+PersonaFileExtension)
	if fileExists(filePath) {
		return nil, NewPersonaError(ErrorAlreadyExists,
			fmt.Sprintf("persona '%s' already exists at %s", name, filePath), nil)
	}
	normalized, err := normalizePersonaBody(name, body)
	if err != nil {
		return nil, err
	}
	if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write persona %s", filePath), err)
	}
	return readPersonaFile(filePath, SourceProject)
}

// Update overwrites an existing project-local persona. If the target
// persona exists only as a library persona, the update is rejected with
// ErrorReadOnlyLibrary.
func (w *ProjectPersonaWriter) Update(name string, body string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to update a persona", nil)
	}
	if err := validateName(name); err != nil {
		return nil, err
	}
	filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
	if !fileExists(filePath) {
		// If a library persona exists, advise the user to fork first.
		libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
		if fileExists(libraryPath) {
			return nil, NewPersonaError(ErrorReadOnlyLibrary,
				fmt.Sprintf("persona '%s' is a library persona and cannot be edited; fork it first", name), nil)
		}
		return nil, NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("project persona '%s' not found", name), nil)
	}
	normalized, err := normalizePersonaBody(name, body)
	if err != nil {
		return nil, err
	}
	if err := os.WriteFile(filePath, []byte(normalized), 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write persona %s", filePath), err)
	}
	return readPersonaFile(filePath, SourceProject)
}

// Delete removes a project-local persona. Library personas are never
// deleted by this method.
func (w *ProjectPersonaWriter) Delete(name string) error {
	if w.workingDir == "" {
		return NewPersonaError(ErrorNoProjectContext, "a project working directory is required to delete a persona", nil)
	}
	if err := validateName(name); err != nil {
		return err
	}
	filePath := filepath.Join(w.loader.projectDir, name+PersonaFileExtension)
	if !fileExists(filePath) {
		libraryPath := filepath.Join(w.loader.personasDir, name+PersonaFileExtension)
		if fileExists(libraryPath) {
			return NewPersonaError(ErrorReadOnlyLibrary,
				fmt.Sprintf("persona '%s' is a library persona and cannot be deleted", name), nil)
		}
		return NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("project persona '%s' not found", name), nil)
	}
	if err := os.Remove(filePath); err != nil {
		return NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to delete persona %s", filePath), err)
	}
	return nil
}

// Fork copies a library persona into the project-local directory.
// `newName` may be empty to reuse the library name; if the target already
// exists, ErrorAlreadyExists is returned.
func (w *ProjectPersonaWriter) Fork(libraryName, newName string) (*Persona, error) {
	if w.workingDir == "" {
		return nil, NewPersonaError(ErrorNoProjectContext, "a project working directory is required to fork a persona", nil)
	}
	libraryPath := filepath.Join(w.loader.personasDir, libraryName+PersonaFileExtension)
	if !fileExists(libraryPath) {
		return nil, NewPersonaError(ErrorPersonaNotFound,
			fmt.Sprintf("library persona '%s' not found", libraryName), nil)
	}
	targetName := newName
	if targetName == "" {
		targetName = libraryName
	}
	if err := validateName(targetName); err != nil {
		return nil, err
	}
	content, err := os.ReadFile(libraryPath)
	if err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to read library persona %s", libraryPath), err)
	}
	if targetName != libraryName {
		// Rewrite the frontmatter name so the forked file matches its new
		// filename and is discoverable under the new name.
		content = []byte(rewriteFrontmatterName(string(content), targetName))
	}
	if err := os.MkdirAll(w.loader.projectDir, 0o755); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to create project personas directory %s", w.loader.projectDir), err)
	}
	targetPath := filepath.Join(w.loader.projectDir, targetName+PersonaFileExtension)
	if fileExists(targetPath) {
		return nil, NewPersonaError(ErrorAlreadyExists,
			fmt.Sprintf("persona '%s' already exists at %s", targetName, targetPath), nil)
	}
	if err := os.WriteFile(targetPath, content, 0o644); err != nil {
		return nil, NewPersonaError(ErrorFileOperation,
			fmt.Sprintf("failed to write forked persona %s", targetPath), err)
	}
	return readPersonaFile(targetPath, SourceProject)
}

// ProjectDir returns the absolute path to the project-local persona dir.
func (w *ProjectPersonaWriter) ProjectDir() string { return w.loader.projectDir }

// validateName keeps names safe for filesystem use.
func validateName(name string) error {
	trimmed := strings.TrimSpace(name)
	if trimmed == "" {
		return NewPersonaError(ErrorValidation, "persona name cannot be empty", nil)
	}
	if strings.ContainsAny(trimmed, "/\\") || strings.HasPrefix(trimmed, ".") {
		return NewPersonaError(ErrorValidation,
			fmt.Sprintf("invalid persona name %q", name), nil)
	}
	return nil
}

// normalizePersonaBody ensures the persona body has valid frontmatter and a
// name matching the file name. If the caller supplies a full markdown
// document with frontmatter, the frontmatter's name is forced to `name`.
// If the caller supplies raw body text without frontmatter, a minimal
// frontmatter block is synthesized.
func normalizePersonaBody(name string, body string) (string, error) {
	body = strings.TrimLeft(body, "\n")
	if body == "" {
		return "", NewPersonaError(ErrorValidation, "persona body cannot be empty", nil)
	}
	if !strings.HasPrefix(body, "---") {
		body = fmt.Sprintf("---\nname: %s\nroles: [general]\ndescription: %s\ntags: []\n---\n\n%s", name, name, body)
	}
	// Validate by parsing.
	parsed, err := parsePersona([]byte(body))
	if err != nil {
		return "", err
	}
	if parsed.Name != name {
		body = rewriteFrontmatterName(body, name)
	}
	return body, nil
}

// rewriteFrontmatterName rewrites the `name:` key in a persona document's
// YAML frontmatter. If no frontmatter is present, the content is returned
// unchanged.
func rewriteFrontmatterName(content string, newName string) string {
	lines := strings.Split(content, "\n")
	if len(lines) == 0 || lines[0] != "---" {
		return content
	}
	end := -1
	for i := 1; i < len(lines); i++ {
		if lines[i] == "---" {
			end = i
			break
		}
	}
	if end == -1 {
		return content
	}
	frontmatter := strings.Join(lines[1:end], "\n")
	var node yaml.Node
	if err := yaml.Unmarshal([]byte(frontmatter), &node); err != nil {
		return content
	}
	// node.Content[0] is the document's mapping node.
	if len(node.Content) == 0 {
		return content
	}
	mapping := node.Content[0]
	if mapping.Kind != yaml.MappingNode {
		return content
	}
	foundName := false
	for i := 0; i < len(mapping.Content); i += 2 {
		if mapping.Content[i].Value == "name" {
			mapping.Content[i+1].Value = newName
			foundName = true
			break
		}
	}
	if !foundName {
		mapping.Content = append([]*yaml.Node{
			{Kind: yaml.ScalarNode, Value: "name"},
			{Kind: yaml.ScalarNode, Value: newName},
		}, mapping.Content...)
	}
	rewritten, err := yaml.Marshal(&node)
	if err != nil {
		return content
	}
	newFrontmatter := strings.TrimRight(string(rewritten), "\n")
	var b strings.Builder
	b.WriteString("---\n")
	b.WriteString(newFrontmatter)
	b.WriteString("\n---\n")
	if end+1 < len(lines) {
		b.WriteString(strings.Join(lines[end+1:], "\n"))
	}
	return b.String()
}

package cmd

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
	"text/tabwriter"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/persona"
